@page "/privacy"
@using Microsoft.AspNetCore.Components.Routing
@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application collects minimal data necessary to provide its services.
    We use cookies to remember your preferences and improve your experience.
</p>

<h2>Cookie Consent</h2>

@if (HasConsent)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy. Thank you!
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>What We Collect</h2>
<ul>
    <li>Essential cookies for site functionality</li>
    <li>Consent preferences</li>
</ul>

<h2>Your Rights</h2>
<p>
    You may withdraw consent at any time by clearing your browser cookies
    and revisiting this page.
</p>

@code {
    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    private bool HasConsent { get; set; }

    protected override void OnInitialized()
    {
        HasConsent = HttpContext.Request.Cookies.ContainsKey("consent");
    }
}

